  /**
   * Faz upload de alimentos a partir do CSV da Tabela Brasileira de Composiï؟½ï؟½o de Alimentos (TACO). Requer autenticaï؟½ï؟½o ADMIN. Pode enviar um arquivo CSV ou usar o arquivo padrï؟½o (public/alimentos.csv).
   * @summary Upload de alimentos do CSV TACO
   */
  const uploadFoods = (
    uploadFoodsBody: BodyType<UploadFoodsBody>,
    options?: SecondParameter<typeof customInstance<UploadFoods200>>,
  ) => {
    const formData = new FormData();
    if (uploadFoodsBody.file !== undefined) {
      formData.append(`file`, uploadFoodsBody.file);
    }
    if (uploadFoodsBody.skipDuplicates !== undefined) {
      formData.append(
        `skipDuplicates`,
        uploadFoodsBody.skipDuplicates.toString(),
      );
    }
    if (uploadFoodsBody.batchSize !== undefined) {
      formData.append(`batchSize`, uploadFoodsBody.batchSize.toString());
    }

    return customInstance<UploadFoods200>(
      { url: `/api/foods/upload`, method: "POST", data: formData },
      options,
    );
  };

